descriptor.controllerScript:
self.onInit = function() {
    var vm = self.ctx.$scope;
    vm.status = 'Widget initialized - waiting for data...';
    vm.tempValue = null;
    console.log('Minimal Test: onInit');
};

self.onDataUpdated = function() {
    var vm = self.ctx.$scope;
    var data = self.ctx.data;
    var found = false;
    if (data && data.length > 0) {
        for (var i = 0; i < data.length; i++) {
            var item = data[i];
            if (item.dataKey && item.dataKey.name === 'temperature' && item.data && item.data.length > 0) {
                vm.tempValue = item.data[0][1];
                vm.status = 'Data received!';
                found = true;
                break;
            }
        }
    }
    if (!found) {
        vm.status = 'Waiting for temperature data...';
    }
    console.log('Minimal Test: onDataUpdated', data);
};

self.onDestroy = function() {
    console.log('Minimal Test: onDestroy');
};
